const items = $input.all();
const tz = 'America/Mexico_City';

// Calcular 'ayer' en la zona horaria de operaciones (yyyy-MM-dd)
const fmt = new Intl.DateTimeFormat('en-CA', { timeZone: tz, year: 'numeric', month: '2-digit', day: '2-digit' });
const nowLocal = new Date();
const yesterday = new Date(nowLocal.getTime() - 24 * 60 * 60 * 1000);
const yyyyMMdd = fmt.format(yesterday);

const filtered = items.filter(i => {
  const ts = i.json.timestamp;
  if (!ts || typeof ts !== 'string') return false;
  // El timestamp es ISO-8601 UTC; convertir a fecha local
  const d = new Date(ts);
  if (isNaN(d.getTime())) return false;
  return fmt.format(d) === yyyyMMdd;
});

if (filtered.length === 0) {
  return [{
    json: {
      hasData: false,
      fecha: yyyyMMdd,
      count: 0
    }
  }];
}

const scores = filtered.map(i => Number(i.json.score) || 0);
const avgScore = Math.round(scores.reduce((a, b) => a + b, 0) / scores.length);
const maxScore = Math.max(...scores);
const minScore = Math.min(...scores);

const niveles = filtered.reduce((acc, i) => {
  const nivel = (i.json.nivel || 'Desconocido').toString();
  acc[nivel] = (acc[nivel] || 0) + 1;
  return acc;
}, {});

const splitCsv = (s) => (s || '').toString().split(',').map(x => x.trim()).filter(Boolean);
const allFortalezas = filtered.flatMap(i => splitCsv(i.json.fortalezas));
const allRedFlags = filtered.flatMap(i => splitCsv(i.json.red_flags));

// Conteo por frecuencia para identificar patrones
const tally = (arr) => {
  const map = new Map();
  for (const s of arr) map.set(s, (map.get(s) || 0) + 1);
  return [...map.entries()]
    .sort((a, b) => b[1] - a[1])
    .slice(0, 5)
    .map(([texto, veces]) => `${texto} (x${veces})`);
};

const datosFormateados = filtered.map((i, idx) => {
  const j = i.json;
  return `${idx + 1}. ${j.nombre_archivo || 'sin-nombre'} | score=${j.score} | nivel=${j.nivel} | rec=${j.recomendacion}`;
}).join('\n');

return [{
  json: {
    hasData: true,
    fecha: yyyyMMdd,
    count: filtered.length,
    avgScore,
    maxScore,
    minScore,
    niveles,
    topFortalezas: tally(allFortalezas),
    topRedFlags: tally(allRedFlags),
    datosFormateados
  }
}];

