parameters.jsCode:
const item = $input.item.json;

if (item.stop_reason === 'max_tokens') {
  throw new Error('Respuesta de Claude truncada (max_tokens alcanzado). El JSON está incompleto.');
}

const rawText = item.content?.[0]?.text ?? '';

let parsed;
try {
  const cleaned = rawText.trim().replace(/^```json\s*/i, '').replace(/```\s*$/, '').trim();
  parsed = JSON.parse(cleaned);
} catch (err) {
  throw new Error('No se pudo parsear el JSON de Claude: ' + err.message + ' | raw=' + rawText.substring(0, 200));
}

delete parsed.pensamiento;

const meta = $('AggregateAndFilter').item.json;

return {
  json: {
    timestamp: new Date().toISOString(),
    fecha: meta.fecha,
    count: meta.count,
    avgScore: meta.avgScore,
    maxScore: meta.maxScore,
    minScore: meta.minScore,
    niveles: meta.niveles,
    resumen: parsed.resumen || '',
    observaciones: Array.isArray(parsed.observaciones) ? parsed.observaciones : [],
    alertas: Array.isArray(parsed.alertas) ? parsed.alertas : [],
    recomendacion: parsed.recomendacion || ''
  }
};

const j = $input.item.json;

const nivelesTxt = Object.entries(j.niveles || {})
  .map(([k, v]) => `${k}: ${v}`)
  .join(' · ') || 'sin datos';

const bullets = (arr, emoji) => (arr && arr.length
  ? arr.map(x => `${emoji} ${x}`).join('\n')
  : `${emoji} _ninguno_`);

const blocks = [
  {
    type: 'header',
    text: { type: 'plain_text', text: `📊 Resumen Operativo — ${j.fecha}`, emoji: true }
  },
  {
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: `*CVs evaluados:*\n${j.count}` },
      { type: 'mrkdwn', text: `*Score promedio:*\n${j.avgScore} (min ${j.minScore} · max ${j.maxScore})` },
      { type: 'mrkdwn', text: `*Distribución:*\n${nivelesTxt}` },
      { type: 'mrkdwn', text: `*Recomendación:*\n${j.recomendacion || '—'}` }
    ]
  },
  { type: 'divider' },
  {
    type: 'section',
    text: { type: 'mrkdwn', text: `*Resumen:*\n${j.resumen || '_sin resumen_'}` }
  },
  {
    type: 'section',
    text: { type: 'mrkdwn', text: `*Observaciones*\n${bullets(j.observaciones, '•')}` }
  },
  {
    type: 'section',
    text: { type: 'mrkdwn', text: `*Alertas*\n${bullets(j.alertas, '⚠️')}` }
  },
  {
    type: 'context',
    elements: [
      { type: 'mrkdwn', text: `_Generado automáticamente por n8n + Claude API · ${j.timestamp}_` }
    ]
  }
];

return {
  json: {
    ...j,
    blocks,
    fallbackText: `Resumen Operativo ${j.fecha}: ${j.count} CVs, promedio ${j.avgScore}`
  }
};

const payload = $input.first()?.json ?? {};
const err = payload.error ?? payload;
const message = err?.message ?? (typeof err === 'string' ? err : JSON.stringify(err));

let agg = {};
try { agg = $('AggregateAndFilter').item.json; } catch (e) { /* agg sigue vacío */ }

return [{
  json: {
    ok: false,
    error: message,
    timestamp: new Date().toISOString(),
    fecha: agg.fecha ?? new Date(Date.now() - 86400000).toISOString().split('T')[0],
    count: agg.count ?? 0,
    avgScore: agg.avgScore ?? 0
  }
}];
